<script lang="ts">
 import {estimateTokens,type PromptBlock,type PromptPreset,type PromptRole} from '@simbot/risu';
 let {presets,active,onselect,onchange,onnew,onclone,onrename,onremove,onimport,onexport}:{presets:PromptPreset[];active:PromptPreset;onselect:(id:string)=>void;onchange:(p:PromptPreset)=>void;onnew:()=>void;onclone:()=>void;onrename:()=>void;onremove:()=>void;onimport:(file:File)=>void;onexport:()=>void}=$props();let drag=$state<number|null>(null);const blockTypes=['plain','cot','chat','description','persona','lorebook','authornote','memory','postEverything','cache','engineFacts','availableActions','groundedMemory'] as const;
 const estimate=(b:PromptBlock)=>estimateTokens('text'in b?b.text:'innerFormat'in b?b.innerFormat??'':'');function update(index:number,patch:Record<string,unknown>){const copy=structuredClone(active),block=copy.blocks[index] as unknown as Record<string,unknown>;Object.assign(block,patch);onchange(copy);}function changeType(index:number,type:typeof blockTypes[number]){const old=active.blocks[index]!,base={id:old.id,name:old.name,enabled:old.enabled,source:old.source};let block:PromptBlock;if(type==='plain'||type==='cot')block={...base,type,role:'system',text:'',slot:'normal'};else if(type==='chat')block={...base,type,rangeStart:-40,rangeEnd:'end'};else if(type==='cache')block={...base,type,depth:0,role:'all'};else if(type==='engineFacts'||type==='availableActions'||type==='groundedMemory')block={...base,type,role:'system'};else block={...base,type,role:'system'};const copy=structuredClone(active);copy.blocks[index]=block;onchange(copy);}function drop(to:number){if(drag==null||drag===to)return;const copy=structuredClone(active),[item]=copy.blocks.splice(drag,1);if(item)copy.blocks.splice(to,0,item);drag=null;onchange(copy);}
</script>
<section class="prompt"><div class="top"><select value={active.id} onchange={(e)=>onselect(e.currentTarget.value)}>{#each presets as p}<option value={p.id}>{p.name}</option>{/each}</select><div><button onclick={onnew}>＋</button><button onclick={onclone}>복제</button><button onclick={onrename}>이름</button><button onclick={onremove}>삭제</button></div><label class="file">리스 JSON<input type="file" accept=".json" onchange={(e)=>{const f=e.currentTarget.files?.[0];if(f)onimport(f);e.currentTarget.value='';}}/></label><button onclick={onexport}>내보내기</button></div><small>토큰 수는 한·영 문자 비중을 반영한 근사치이며 모델마다 다를 수 있습니다.</small>
 <div class="blocks">{#each active.blocks as block,i (block.id)}<details draggable="true" ondragstart={()=>drag=i} ondragover={(e)=>e.preventDefault()} ondrop={()=>drop(i)}><summary><span>⠿</span><input type="checkbox" checked={block.enabled} disabled={block.type==='unsupported'} onchange={(e)=>update(i,{enabled:e.currentTarget.checked})}/><b>{block.name}</b><em>{block.type}</em><i>≈{estimate(block)}</i></summary><div class="edit"><label>이름<input value={block.name} oninput={(e)=>update(i,{name:e.currentTarget.value})}/></label>{#if 'role'in block&&block.role!=='all'}<label>role<select value={block.role} onchange={(e)=>update(i,{role:e.currentTarget.value as PromptRole})}><option>system</option><option>user</option><option>assistant</option></select></label>{/if}{#if 'text'in block}<label>텍스트<textarea rows="5" value={block.text} oninput={(e)=>update(i,{text:e.currentTarget.value})}></textarea></label>{/if}{#if 'innerFormat'in block}<label>innerFormat<textarea rows="3" value={block.innerFormat??''} oninput={(e)=>update(i,{innerFormat:e.currentTarget.value})}></textarea></label>{/if}{#if block.type==='authornote'}<label>depth<input type="number" value={block.depth??0} oninput={(e)=>update(i,{depth:Number(e.currentTarget.value)})}/></label>{/if}{#if block.type==='chat'}<label>rangeStart<input type="number" value={block.rangeStart} oninput={(e)=>update(i,{rangeStart:Number(e.currentTarget.value)})}/></label><label>rangeEnd<input value={block.rangeEnd} oninput={(e)=>update(i,{rangeEnd:e.currentTarget.value==='end'?'end':Number(e.currentTarget.value)})}/></label>{/if}{#if block.type==='unsupported'}<p class="warn">{block.originalType}: {block.reason}</p>{/if}</div></details>{/each}</div>
</section>
<style>.prompt{display:grid;gap:10px}.top{display:grid;gap:6px}.top>div{display:flex;gap:4px}.top button,.top select,.file{font-size:11px}.top button{border:1px solid #3b414d;background:#171a20;color:#ddd;border-radius:4px}.top button:hover{border-color:#6c98f4;background:#252a34}.top button:active{transform:scale(.97)}button:focus-visible,input:focus-visible,select:focus-visible,textarea:focus-visible{outline:2px solid #6c98f4;outline-offset:2px}.file input{display:none}.blocks{display:grid;gap:6px}details{border:1px solid #343945;border-radius:7px;background:#181b21}summary{display:flex;align-items:center;gap:6px;padding:8px;cursor:grab;font-size:11px}summary:hover{background:#20242c}summary b{overflow:hidden;text-overflow:ellipsis}summary em{margin-left:auto;color:#7f8795}summary i{color:#6f95df}.edit{display:grid;gap:7px;padding:9px;border-top:1px solid #343945}.edit label{display:grid;gap:3px;font-size:10px}.edit input,.edit select,.edit textarea,.top select{background:#11141a;color:#ddd;border:1px solid #3b414d;border-radius:4px;padding:5px}.warn{color:#e4a3ad;font-size:11px}</style>
